#include <iostream>
#include <string>
#include <iomanip>

class Product {
private:
    std::string productName;
    double price;

public:
    Product() : productName(""), price(0.0) {}
    Product(std::string name, double p) : productName(name), price(p) {}

    std::string getProductName() {
        return productName;
    }

    double getPrice() {
        return price;
    }

    void setProductName(std::string name) {
        productName = name;
    }

    void setPrice(double p) {
        price = p;
    }
};

int main() {
    Product p1;
    p1.setProductName("Monitor");
    p1.setPrice(350.75);

    std::cout << "Product: " << p1.getProductName() << ", Price: $" << std::fixed << std::setprecision(2) << p1.getPrice() << std::endl;

    p1.setProductName("Gaming Monitor");
    p1.setPrice(499.99);
    std::cout << "Product: " << p1.getProductName() << ", Price: $" << std::fixed << std::setprecision(2) << p1.getPrice() << std::endl;

    Product p2("Mouse", 25.00);
    std::cout << "Product: " << p2.getProductName() << ", Price: $" << std::fixed << std::setprecision(2) << p2.getPrice() << std::endl;

    return 0;
}
